Private VLAN Promiscuous.commands:
description {{ description }}
switchport private-vlan mapping {{ pvlan_primary }} {{ pvlan_isolated }}
switchport mode private-vlan promiscuous
spanning-tree portfast
spanning-tree bpduguard enable
no shut

Private VLAN Isolated.commands:
description {{ description }}
switchport private-vlan host-association {{ pvlan_primary }} {{ pvlan_isolated }}
switchport private-vlan mapping {{ pvlan_primary }} {{ pvlan_isolated }}
switchport mode private-vlan host
no shutdown
spanning-tree portfast
spanning-tree bpduguard enable

Trunk Uplink to Switch.commands:
description {{ description }}
switchport trunk native vlan {{ native_vlan }}
switchport trunk allowed vlan {{ trunk_allowed }}
switchport mode trunk
switchport nonegotiate
no shutdown

Trunk Uplink to Firewall.commands:
description {{ description }}
switchport trunk allowed vlan {{ trunk_allowed }}
switchport mode trunk
switchport nonegotiate
no shutdown

Access Port.commands:
description {{ description }}
switchport access vlan {{ access_vlan }}
switchport mode access
no shutdown
spanning-tree portfast
spanning-tree bpduguard enable
